-- profiles tablosuna günlük görev takibi için JSONB sütunu ekleme
ALTER TABLE public.profiles ADD COLUMN IF NOT EXISTS daily_missions JSONB DEFAULT ('{"date": "' || TO_CHAR(NOW(), 'YYYY-MM-DD') || '", "tasks": [{"id": "use_tool", "target": 5, "current": 0, "claimed": false, "reward": 100, "type": "coins", "label_tr": "5 Yardımcı Araç Kullan", "label_en": "Use 5 Tools"}, {"id": "find_word", "target": 30, "current": 0, "claimed": false, "reward": 150, "type": "coins", "label_tr": "30 Kelime Bul", "label_en": "Find 30 Words"}, {"id": "play_game", "target": 3, "current": 0, "claimed": false, "reward": 250, "type": "xp", "label_tr": "3 Oyun Seansı Tamamla", "label_en": "Complete 3 Game Sessions"}]}')::jsonb;
